      const prev = view[key] ?? { region: event.region, month: event.completedAt.slice(0, 7), completed: 0 };
      return { ...view, [key]: { ...prev, completed: prev.completed + 1 } };
    }
    case "scheduled":
    case "cancelled":
      return view;
    default: {
      const _: never = event;
      return _;
    }
  }
}
