export async function appendCampaignStop(
  store: EventStore<CampaignStopEvent>,
  stream: string,
  newEvents: CampaignStopEvent[],
  expectedRevision: bigint | "no_stream" | "any",
): Promise<bigint> {
  try {
    const { nextRevision } = await store.appendToStream(stream, newEvents, { expectedRevision });
    return nextRevision;
  } catch (err) {
    if (err instanceof Error && /revision|conflict|version/i.test(err.message)) {
      throw new ConcurrencyConflict(err.message);
    }
    throw err;
  }
}
