  | { type: "registered"; benefactorId: string; name: string }
  | { type: "pledged"; benefactorId: string; amount: number };

export interface StoredEvent<E> { globalPosition: bigint; event: E }

export interface EventReader<E> {
  readBatch(from: bigint, size: number): Promise<StoredEvent<E>[]>;
}

export interface BenefactorView { id: string; name: string; totalPledged: number }

export interface ReadStore {
  clear(): Promise<void>;
  persistBatch(rows: BenefactorView[]): Promise<void>;
}

export function project(view: Record<string, BenefactorView>, event: BenefactorRegistryEvent): Record<string, BenefactorView> {
  switch (event.type) {
    case "registered":
      return { ...view, [event.benefactorId]: { id: event.benefactorId, name: event.name, totalPledged: 0 } };
    case "pledged": {
      const row = view[event.benefactorId];
      if (!row) return view;
      return { ...view, [event.benefactorId]: { ...row, totalPledged: row.totalPledged + event.amount } };
    }
    default: {
      const _: never = event;
      return _;
    }
  }
}

export async function rebuild(opts: {
  from: bigint;
  batchSize: number;
  reader: EventReader<BenefactorRegistryEvent>;
  store: ReadStore;
  onProgress?: (position: bigint) => void;
}): Promise<void> {
  if (opts.from === 0n) await opts.store.clear();
  let cursor = opts.from;
  let view: Record<string, BenefactorView> = {};
  for (;;) {
    const batch = await opts.reader.readBatch(cursor, opts.batchSize);
    if (batch.length === 0) break;
    for (const stored of batch) {
      view = project(view, stored.event);
      cursor = stored.globalPosition;
    }
    await opts.store.persistBatch(Object.values(view));
    opts.onProgress?.(cursor);
  }
}
