      cursor = s.globalPosition;
    }
    await opts.store.save(Object.values(view));
  }
  return cursor;
}
```

CQRS splits the write and read sides. Writes flow through a command handler that loads state, calls decide, and appends events. Reads come from a read model kept up to date by a projection subscribing to the same event stream. The read model is eventually consistent with the event store; the two sides share the event union but NOT the state type.

```typescript
export type EndowmentFundEvent =
  | { type: "opened"; fundId: string; name: string }
  | { type: "contributed"; fundId: string; amount: number };

export type EndowmentFundCommand =
  | { type: "open"; fundId: string; name: string }
  | { type: "contribute"; amount: number };

interface WriteState { status: "none" | "open"; name?: string; balance: number }
const initial: WriteState = { status: "none", balance: 0 };

function evolve(s: WriteState, e: EndowmentFundEvent): WriteState {
  switch (e.type) {
    case "opened":
      return { status: "open", name: e.name, balance: 0 };
    case "contributed":
      return { ...s, balance: s.balance + e.amount };
    default: {
      const _: never = e;
      return _;
    }
  }
}

function decide(c: EndowmentFundCommand, s: WriteState): EndowmentFundEvent[] {
  switch (c.type) {
    case "open":
      if (s.status !== "none") throw new Error("exists");
      return [{ type: "opened", fundId: c.fundId, name: c.name }];
    case "contribute":
      if (s.status !== "open") throw new Error("closed");
      return [{ type: "contributed", fundId: "?", amount: c.amount }];
    default: {
      const _: never = c;
      return _;
    }
  }
}

export interface EventStore<E> {
  readStream(s: string): Promise<E[]>;
  appendToStream(s: string, e: E[]): Promise<void>;
}
export interface ReadView { fundId: string; name: string; balance: number }
export interface ReadStore { find(id: string): Promise<ReadView | null> }

// read store is eventually consistent with the write side
export async function handleCommand(
  cmd: EndowmentFundCommand,
  stream: string,
  store: EventStore<EndowmentFundEvent>,
): Promise<void> {
  const events = await store.readStream(stream);
  const state = events.reduce<WriteState>(evolve, initial);
  await store.appendToStream(stream, decide(cmd, state));
}

export function queryView(id: string, reads: ReadStore): Promise<ReadView | null> {
  return reads.find(id);
}
