An event-sourced aggregate is reconstructed by folding its event history with a pure evolve function over an initial state literal. There is no persisted state; the stream IS the source of truth. Replaying the events in order yields the current state.

```typescript
export type VolunteerShiftEvent =
  | { type: "started"; shiftId: string; volunteerId: string; role: string }
  | { type: "extended"; hours: number }
  | { type: "ended"; endedAt: string };

export interface VolunteerShiftState {
  shiftId: string | null;
  volunteerId: string | null;
  role: string | null;
  hours: number;
  endedAt: string | null;
}

export const initialState: VolunteerShiftState = {
  shiftId: null,
  volunteerId: null,
  role: null,
  hours: 0,
  endedAt: null,
};

export function evolve(s: VolunteerShiftState, e: VolunteerShiftEvent): VolunteerShiftState {
  switch (e.type) {
    case "started":
      return { ...s, shiftId: e.shiftId, volunteerId: e.volunteerId, role: e.role };
    case "extended":
      return { ...s, hours: s.hours + e.hours };
    case "ended":
      return { ...s, endedAt: e.endedAt };
    default: {
      const _: never = e;
      return _;
    }
  }
}

export function aggregate(events: VolunteerShiftEvent[]): VolunteerShiftState {
  return events.reduce(evolve, initialState);
}
