import { Effect } from "effect";

export class DomainError extends Error {}
export class ConcurrencyConflict extends Error {}

export type EndowmentFundState =
  | { status: "none" }
  | { status: "open"; id: string; balance: number }
  | { status: "closed"; id: string };

export type EndowmentFundCommand =
  | { type: "open"; id: string }
  | { type: "contribute"; amount: number }
  | { type: "close" };

export type EndowmentFundEvent =
  | { type: "opened"; id: string }
  | { type: "contributed"; amount: number }
  | { type: "closed" };

const initial: EndowmentFundState = { status: "none" };

function evolve(s: EndowmentFundState, e: EndowmentFundEvent): EndowmentFundState {
  switch (e.type) {
    case "opened":
      return { status: "open", id: e.id, balance: 0 };
    case "contributed":
      return s.status === "open" ? { ...s, balance: s.balance + e.amount } : s;
    case "closed":
      return s.status === "open" ? { status: "closed", id: s.id } : s;
    default: {
      const _: never = e;
      return _;
    }
  }
}

function decide(c: EndowmentFundCommand, s: EndowmentFundState): EndowmentFundEvent[] {
  switch (c.type) {
    case "open":
      if (s.status !== "none") throw new DomainError("exists");
      return [{ type: "opened", id: c.id }];
    case "contribute":
      if (s.status !== "open") throw new DomainError("not open");
      if (c.amount <= 0) throw new DomainError("amount must be positive");
      return [{ type: "contributed", amount: c.amount }];
    case "close":
      if (s.status !== "open") throw new DomainError("not open");
      return [{ type: "closed" }];
    default: {
      const _: never = c;
      return _;
    }
  }
}

export interface StoredEvent<E> { revision: bigint; event: E }
export interface EventStore<E> {
  readStream(s: string): Promise<StoredEvent<E>[]>;
  appendToStream(s: string, e: E[], o: { expectedRevision: bigint | "no_stream" }): Promise<void>;
}

export function handle(
  command: EndowmentFundCommand,
  ctx: { streamName: string; eventStore: EventStore<EndowmentFundEvent> },
): Effect.Effect<void, Error, never> {
  return Effect.gen(function* () {
    const stored = yield* Effect.promise(() => ctx.eventStore.readStream(ctx.streamName));
    const state = stored.reduce<EndowmentFundState>((s, r) => evolve(s, r.event), initial);
    const expectedRevision: bigint | "no_stream" = stored.length === 0 ? "no_stream" : stored[stored.length - 1].revision;
    const events = decide(command, state);
    yield* Effect.tryPromise({
      try: () => ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision }),
      catch: (u) => new ConcurrencyConflict(String(u)),
    });
  });
}
